import { useState } from "react";

function CardCarrito() {

    const [contador, setContador] = useState(0)

    function restarCont(){
        setContador(contador-1)
    }
    function sumarCont(){
        setContador(contador+1)
    }

    return (
        <div class="card-carrito">
            <img src="./burguer.jpg"/>
                <div class="card-texto">
                    <h3>hamburguesa 1</h3>
                    <span>$12349</span>
                    <p>Lorem ipsum dolor sit amet consectetur adipisicing elit. Totam suscipit placeat, doloremque porro
                        esse, quidem quae, aperiam dolores sed consequatur delectus laudantium impedit alias. Repellendus
                        esse fugiat odio consectetur natus!
                    </p>
                </div>
                <div class="btns-card">
                    <button type="submit">Eliminar</button>
                    <div class="contador">
                        <button type="submit" onClick={restarCont} class="btn--">-</button>
                        <p>{contador}</p>
                        <button type="submit" onClick={sumarCont} class="btn---">+</button>
                    </div>
                </div>
        </div>
    )
}

export default CardCarrito;
